import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.ZhLefgN8.js";const p=JSON.parse('{"title":"美股交易规则与结算","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/trading-hours-and-rules/us-trading-rules.md","filePath":"zh-CN/stock-trading/trading-hours-and-rules/us-trading-rules.md"}'),l={name:"stock-trading/trading-hours-and-rules/us-trading-rules.md"};function d(h,a,o,n,s,u){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="美股交易规则与结算" tabindex="-1">美股交易规则与结算 <a class="header-anchor" href="#美股交易规则与结算" aria-label="Permalink to &quot;美股交易规则与结算&quot;">​</a></h1><p>美股四个交易时段、日内交易、T+1 交收、盘前盘后夜盘规则及 ADR、PTP、OTC 交易说明。</p><h2 id="交易时间总览" tabindex="-1">交易时间总览 <a class="header-anchor" href="#交易时间总览" aria-label="Permalink to &quot;交易时间总览&quot;">​</a></h2><p>美股提供夜盘、盘前、盘中、盘后四个交易时段，组成 24 小时交易体系。</p><p>夏令时为每年 3 月第二个星期日至 11 月第一个星期日，冬令时为每年 11 月第一个星期日至次年 3 月第二个星期日。</p><table tabindex="0"><thead><tr><th>时段</th><th>美东时间</th><th>北京时间（夏令时）</th><th>北京时间（冬令时）</th></tr></thead><tbody><tr><td>夜盘</td><td>周日至周四 20:00 - 03:50(+1)</td><td>08:00 - 15:50</td><td>09:00 - 16:50</td></tr><tr><td>盘前</td><td>周一至周五 04:00 - 09:30</td><td>16:00 - 21:30</td><td>17:00 - 22:30</td></tr><tr><td>盘中（常规）</td><td>周一至周五 09:30 - 16:00</td><td>21:30 - 04:00(+1)</td><td>22:30 - 05:00(+1)</td></tr><tr><td>盘后</td><td>周一至周五 16:00 - 20:00</td><td>04:00 - 08:00</td><td>05:00 - 09:00</td></tr><tr><td>半日市盘后</td><td>13:00 - 17:00</td><td>01:00 - 05:00</td><td>02:00 - 06:00</td></tr></tbody></table><h2 id="交易与交收机制" tabindex="-1">交易与交收机制 <a class="header-anchor" href="#交易与交收机制" aria-label="Permalink to &quot;交易与交收机制&quot;">​</a></h2><h3 id="日内交易" tabindex="-1">日内交易 <a class="header-anchor" href="#日内交易" aria-label="Permalink to &quot;日内交易&quot;">​</a></h3><p>日内交易（Day Trade）是指在同一交易日内对某只股票或期权进行买入卖出，也称 T+0 交易。长桥账户可进行无限次日内交易。</p><h3 id="卖空规则" tabindex="-1">卖空规则 <a class="header-anchor" href="#卖空规则" aria-label="Permalink to &quot;卖空规则&quot;">​</a></h3><p>支持美股卖空。</p><h3 id="清算规则" tabindex="-1">清算规则 <a class="header-anchor" href="#清算规则" aria-label="Permalink to &quot;清算规则&quot;">​</a></h3><p>美股实行 T+1 交割制度，即交易发生后第一个工作日完成清算交割。</p><h3 id="最小交易单位与涨跌幅" tabindex="-1">最小交易单位与涨跌幅 <a class="header-anchor" href="#最小交易单位与涨跌幅" aria-label="Permalink to &quot;最小交易单位与涨跌幅&quot;">​</a></h3><p>美股最小交易单位为 1 股，支持碎股交易，没有单日涨跌幅限制。</p><h3 id="价格最小变动单位" tabindex="-1">价格最小变动单位 <a class="header-anchor" href="#价格最小变动单位" aria-label="Permalink to &quot;价格最小变动单位&quot;">​</a></h3><ul><li>1 美元以下：0.0001 美元</li><li>1 美元以上：0.01 美元</li></ul><h2 id="盘前盘后交易" tabindex="-1">盘前盘后交易 <a class="header-anchor" href="#盘前盘后交易" aria-label="Permalink to &quot;盘前盘后交易&quot;">​</a></h2><p>美股允许在常规交易时段外进行盘前盘后交易，委托单会被提交到交易所进行对盘撮合。</p><h2 id="夜盘交易" tabindex="-1">夜盘交易 <a class="header-anchor" href="#夜盘交易" aria-label="Permalink to &quot;夜盘交易&quot;">​</a></h2><h3 id="基本规则" tabindex="-1">基本规则 <a class="header-anchor" href="#基本规则" aria-label="Permalink to &quot;基本规则&quot;">​</a></h3><ul><li>夜盘时段：美东时间周日至周四 20:00 - 03:50(+1)</li><li>每周第一个夜盘为周日晚 20:00 至周一凌晨 03:50，最后一个为周四晚 20:00 至周五凌晨 03:50</li><li>夜盘是交易日的起始，美东 20:00 开始的夜盘归属于下个交易日（如周一晚的夜盘归属周二）</li></ul><h3 id="可交易标的" tabindex="-1">可交易标的 <a class="header-anchor" href="#可交易标的" aria-label="Permalink to &quot;可交易标的&quot;">​</a></h3><p>支持部分股票和 ETF，总市值大于 5 亿。可通过股票详情页的「24H」标签识别是否支持夜盘交易，标的范围持续扩展。</p><h3 id="下单方式" tabindex="-1">下单方式 <a class="header-anchor" href="#下单方式" aria-label="Permalink to &quot;下单方式&quot;">​</a></h3><p>夜盘仅支持限价单，有效期为当日有效。可通过交易大厅选择「仅夜盘」时段下单，或在快捷交易界面点亮夜盘图标下单。</p><h3 id="持仓盈亏" tabindex="-1">持仓盈亏 <a class="header-anchor" href="#持仓盈亏" aria-label="Permalink to &quot;持仓盈亏&quot;">​</a></h3><p>可在设置 - 资产设置 - 资本计算方式中选择是否使用夜盘价。启用后夜盘时段的最新价会影响持仓和盈亏计算。</p><h3 id="夜盘注意事项" tabindex="-1">夜盘注意事项 <a class="header-anchor" href="#夜盘注意事项" aria-label="Permalink to &quot;夜盘注意事项&quot;">​</a></h3><ul><li>夜盘仅支持限价单和当日有效订单，支持卖空</li><li>未完成订单在夜盘收盘后自动撤销</li><li>夜盘属场外交易，上游对订单价格可能有限制</li><li>若标的在 3 天窗口期内有公司行动，订单可能被拒绝</li><li>夜盘交易仅支持综合账户</li><li>流动性较低、价格波动较大，可能部分成交或无法成交</li><li>不支持提前下单</li><li>夜盘遵循交易所节假日历，节假日不交易</li><li>手续费与常规时段一致</li><li>15:50 - 16:00（北京时间）暂不支持交易</li></ul><h2 id="adr-美国存托凭证" tabindex="-1">ADR 美国存托凭证 <a class="header-anchor" href="#adr-美国存托凭证" aria-label="Permalink to &quot;ADR 美国存托凭证&quot;">​</a></h2><p>美国存托凭证（ADR）是美国银行为协助外国证券在美国交易而发行的可转让证书，代表非美国公司一定数量的股份。</p><h3 id="adr-托管费用" tabindex="-1">ADR 托管费用 <a class="header-anchor" href="#adr-托管费用" aria-label="Permalink to &quot;ADR 托管费用&quot;">​</a></h3><p>ADR 托管费用平均每股 1 至 5 美分，收取金额和时间因不同 ADR 而异。部分 ADR 还会收取股息费用、比例变更费用等。</p><p>托管费用在登记日确定：登记日 T-1 交易日收盘时持有 ADR 即会被收取费用，登记日及之后卖出仍会收取。</p><p>注意：账户没有现金时，费用会通过融资垫付并产生利息。</p><h3 id="查询-adr-费用" tabindex="-1">查询 ADR 费用 <a class="header-anchor" href="#查询-adr-费用" aria-label="Permalink to &quot;查询 ADR 费用&quot;">​</a></h3><ul><li>长桥 App - 资产 - 全部功能 - 资金记录或结单查询</li><li>也可通过四大托管行官网查询：纽约梅隆银行、摩根大通银行、花旗银行、德意志银行</li></ul><h2 id="ptp-公开交易合伙企业" tabindex="-1">PTP 公开交易合伙企业 <a class="header-anchor" href="#ptp-公开交易合伙企业" aria-label="Permalink to &quot;PTP 公开交易合伙企业&quot;">​</a></h2><p>自 2023 年 1 月 1 日起，根据美国国税局规定，非美国人持有或交易 PTP 相关证券时将产生以下税务成本：</p><ul><li>卖出、交易或转移 PTP 证券：按交易总金额 10% 扣缴预扣税</li><li>获得股息分配：按分配总金额 37%（个人投资者）或 21%（公司/机构投资者）扣缴预扣税</li></ul><p>如 PTP 证券发布&quot;合格通知&quot;声明符合豁免条件，则可豁免扣缴。</p><h2 id="otc-场外交易" tabindex="-1">OTC 场外交易 <a class="header-anchor" href="#otc-场外交易" aria-label="Permalink to &quot;OTC 场外交易&quot;">​</a></h2><p>长桥支持交易部分 OTC 市场的股票，OTC 市场股票仅支持美股盘中时段交易。</p><p>如限价订单未送出市场，可能是未满足最小交易数量要求，请调整数量后重试。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/订单类型/限价单与市价单">限价单与市价单</a> — 订单类型</li><li><a href="/wiki/stock-trading/交易时间与规则/美股定投">美股定投</a> — 定投规则与设置</li><li><a href="/wiki/stock-trading/交易时间与规则/美股卖空">美股卖空</a> — 卖空交易规则</li></ul>',47)])])}const b=t(l,[["render",d]]);export{p as __pageData,b as default};
